import React, { Component } from 'react'
import Filters from './Filters.js'

class Commerciaux extends Component {
  state={
    commerciaux:[],
    pages:0,
    page:0,
    next:0,
    previous:0,
    length:0
  }
  get_commerciaux=async(pays="",wilaya="",commune="",commercial="",page="")=>{
    await fetch(this.props.urls.commerciaux
      +`?pays=${pays}&wilaya=${wilaya}&commune=${commune}&commercial=${commercial}&page=${page}`)
    .then(response=>response.json())
    .then(response=>this.setState({commerciaux:response.result,  pages:response.pages,
                                    page:page,
                                    next:response.next,
                                    previous:response.previous,
                                    length:response.length
                                  }))
  }
  componentDidMount(){
    this.props.changeTitle("liste des commerciaux")
    this.get_commerciaux()
  }

  render() {
    return (
      <React.Fragment>
        <Filters
         pays={this.props.pays}
         getCommerciaux={this.get_commerciaux}
         commerciaux={this.state.commerciaux}
         pages={this.state.pages}
         page={this.state.page}
         next={this.state.next}
         previous={this.state.previous}
         length={this.state.length}
         />
      </React.Fragment>
    )
  }
}

export default Commerciaux
