import React, { Component } from 'react'
import List from './List.js'
import Pagination from './Pagination.js'
import DatePicker from "react-datepicker";
import "react-datepicker/dist/react-datepicker.css";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faPrint,faImage} from "@fortawesome/free-solid-svg-icons";


class Filters extends Component {
  state={
    selected_pays:0,
    selected_wilaya:0,
    selected_commune:0,
    medecin:'',
    commercial:'',
    specialite:'',
    classification:'',
    visites:'',
    produit:'',
    min_date:'',
    max_date:'',
    priority:'',
    shared:'',
    stock:""
  }


  componentDidMount(){
    setTimeout(function(){
      document.getElementById('select-init').click()
      // document.getElementById('select-init').dispatchEvent(new MouseEvent("click",{bubbles: true, cancellable: true}));
    },2000)



  }


  PDFLink=()=>{
    return `/rapports/visites/PDF/?pays=${this.state.selected_pays}&wilaya=${this.state.selected_wilaya}&commune=${this.state.selected_commune}&priority=${this.state.priority}&commercial=${this.state.commercial}&medecin=${this.state.medecin}&mindate=${this.state.min_date}&maxdate=${this.state.max_date}&specialite=${this.state.specialite}&classification=${this.state.classification}&produit=${this.state.produit}&visites=${this.state.visites}&shared=${this.state.shared}&stock=${this.state.stock}`
  }
  PDFSingle=()=>{
    return `?priority=${this.state.priority}&mindate=${this.state.min_date}&maxdate=${this.state.max_date}&produit=${this.state.produit}&stock=${this.state.stock}`
  }
  MedecinsList=()=>{
    return `/medecins/list/show/?pays=${this.state.selected_pays}&wilaya=${this.state.selected_wilaya}&commune=${this.state.selected_commune}&priority=${this.state.priority}&commercial=${this.state.commercial}&medecin=${this.state.medecin}&mindate=${this.state.min_date}&maxdate=${this.state.max_date}&specialite=${this.state.specialite}&classification=${this.state.classification}&produit=${this.state.produit}&visites=${this.state.visites}&shared=${this.state.shared}&stock=${this.state.stock}`
  }


  
  get_medecins=()=>{
    this.props.getMedecins(
      this.state.selected_pays,
      this.state.selected_wilaya,
      this.state.selected_commune,
      this.state.medecin,
      this.state.commercial,
      this.state.specialite,
      this.state.classification,
      this.state.visites,
      this.state.produit,
      this.state.min_date,
      this.state.max_date,
      this.state.priority,
      this.state.shared,
      this.state.stock
    )
  }
  get_by_page=(page)=>{
    this.props.getMedecins(
      this.state.selected_pays,
      this.state.selected_wilaya,
      this.state.selected_commune,
      this.state.medecin,
      this.state.commercial,
      this.state.specialite,
      this.state.classification,
      this.state.visites,
      this.state.produit,
      this.state.min_date,
      this.state.max_date,
      this.state.priority,
      this.state.shared,
      this.state.stock,
      page
    )
  }

  min_dateChange=date => {
    try{
      var day=(date.getDate()<10) ? '0'+date.getDate() : date.getDate()
      var month=(date.getMonth()+1<10) ? '0'+(date.getMonth()+1) : (date.getMonth()+1)
      this.min_date_picker=date
      this.setState({min_date: `${date.getFullYear()}-${month}-${day}`},()=>this.get_medecins());
    }catch{
      this.setState({min_date:""},()=>this.get_medecins());this.min_date_picker="";
    }

  };
  max_dateChange=date => {
    try{
      var day=(date.getDate()<10) ? '0'+date.getDate() : date.getDate()
      var month=(date.getMonth()+1<10) ? '0'+(date.getMonth()+1) : (date.getMonth()+1)
      this.max_date_picker=date
      this.setState({max_date: `${date.getFullYear()}-${month}-${day}`},()=>this.get_medecins());
    }catch{
      this.setState({max_date:""},()=>this.get_medecins());this.max_date_picker="";
    }
  };
  render() {
    return (
      <React.Fragment>
      <div className="py-4 container text-secondary">
        <div className="row">
        <div className="col-md pb-2">
          <b>Country:</b>
          <select className="form-control"
          onChange={(e)=>{this.setState({selected_pays:e.target.value,selected_wilaya:0,selected_commune:0},()=>this.get_medecins());
          }}>
          <option value="0">Tous les pays</option>
          {this.props.pays.map(pys=>(
            <option key={pys.id} value={pys.id} >{pys.nom}</option>
          ))}
          </select>
        </div>
          <div className="col-md pb-2">
            <b>Wilaya:</b>
            <select className="form-control"
            onChange={(e)=>{this.setState({selected_wilaya:e.target.value,selected_commune:0},()=>this.get_medecins());
            }}>
            <option value="0">Toutes les wilayas</option>
            {this.props.pays.map(pys=>{
              if((this.state.selected_pays==0) ||(this.state.selected_pays==pys.id))
              return pys.wilayas_list.map(wilaya=>(
                <option key={wilaya.id} value={wilaya.id}>{wilaya.nom}</option>
              ))
            })}
            </select>
          </div>
          <div className="col-md pb-2">
            <b>Commune:</b>
            <select className="form-control"
            onChange={(e)=>{this.setState({selected_commune:e.target.value},()=>this.get_medecins())
            }}>
            <option value="0">Toutes les communes</option>
            {this.props.pays.map(pys=>{
              if((this.state.selected_pays==0) ||(this.state.selected_pays==pys.id))
              return pys.wilayas_list.map(wilaya=>{
                if((this.state.selected_wilaya==0) ||(this.state.selected_wilaya==wilaya.id))
                return wilaya.communes.map(commune=>(
                  <option key={commune.id} value={commune.id}>{commune.nom}</option>
                ))
              })
            })}
            </select>
          </div>


          <div className="col-md pb-2">
            <b>Nom:</b>
            <input type="text" className="form-control"
            onChange={(e)=>{this.setState({medecin:e.target.value},()=>this.get_medecins())
            }}/>
          </div>
          <div className="col-md pb-2">
            <b>Specialite:</b>
            <input  id="medecins_spec" type="text" class="d-none"
            onChange={(e)=>{this.setState({specialite:e.target.value},()=>this.get_medecins())
          }}
            />
            <select className="w-100 multiple" multiple="multiple" data-target={"medecins_spec"}>
            <option value=""> Toutes</option>
            <option value="medicale"> Medicale </option>
            <option value="commerciale"> Commerciale </option>
            {this.props.specialites.map(spec=>(
              <option key={spec.id} value={spec.nom}>{spec.nom}</option>
            ))}
            </select>
          </div>
          <div className="col-md pb-2">
            <b>Classification:</b>
            <input  id="medecins_class" type="text" class="d-none"
            onChange={(e)=>{this.setState({classification:e.target.value},()=>this.get_medecins())
          }}
            />
            <select className="w-100 multiple" multiple="multiple" data-target={"medecins_class"}
            >
            <option value=""> Toutes</option>
            {this.props.classifications.map(classification=>(
              <option key={classification.id} value={classification.nom}>{classification.nom}</option>
            ))}
            </select>
          </div>
          <div className="col-md pb-2">
            <b>Stock:</b>
            <select type="text" className="form-control"
            onChange={(e)=>{this.setState({stock:e.target.value},()=>this.get_medecins());
            }}>
            <option value=""> Tous</option>
            {this.props.produits.map(produit=>{
               if ((produit.pays.includes(parseInt(this.state.selected_pays)))||(this.state.selected_pays==0))
              return(
                <option key={produit.id} value={produit.id}>{produit.nom}</option>
                )
            }
            )}
            </select>
          </div>


        </div>
        <div className="row">
          <div className="col-md pb-2">
            <b>Délégué:</b>
            <select  className="form-control"
            onChange={(e)=>{this.setState({commercial:e.target.value},()=>this.get_medecins())
            }}>
            <option value=""> Tous</option>
            {this.props.commerciaux.map(commercial=>{
              if ((commercial.country==this.state.selected_pays)||(this.state.selected_pays==0))
              return(
                <option key={commercial.id} value={commercial.username}>{commercial.username}</option>
                )
            }
            )}
            </select>
          </div>
          <div className="col-md pb-2">
            <b>Visité:</b>
            <select type="text" className="form-control"
            onChange={(e)=>{this.setState({visites:e.target.value},()=>this.get_medecins());
            }}>
            <option value="">Tous</option>
            <option value="1">Visité</option>
            <option value="0">Non Visité</option>
            <option value="2">Visites Multiples</option>
            </select>
          </div>
          <div className="col-md pb-2">
            <b>Produit:</b>
            <select type="text" className="form-control"
            onChange={(e)=>{this.setState({produit:e.target.value},()=>this.get_medecins());
            }}>
            <option value=""> Tous</option>
            {this.props.produits.map(produit=>{
              if ((produit.pays.includes(parseInt(this.state.selected_pays)))||(this.state.selected_pays==0))
              return(
                <option key={produit.id} value={produit.id}>{produit.nom}</option>
                )
            }
            )}
            </select>
          </div>
          <div className="col-md pb-2">
              <b>Date min:</b><br/>
              <DatePicker className="form-control"  dateFormat="dd/MM/yyyy" selected={this.min_date_picker} onChange={this.min_dateChange} required/>
          </div>
          <div className="col-md pb-2">
              <b>Date max:</b><br/>
              <DatePicker className="form-control"  dateFormat="dd/MM/yyyy" selected={this.max_date_picker} onChange={this.max_dateChange} required/>
          </div>
          <div className="col-md pb-2">
            <b>Priorité:</b>
            <select className="form-control"
             onChange={(e)=>{
               this.setState({priority:e.target.value},()=>this.get_medecins());
              }}>
              <option value="0">0</option>
              <option value="1">1</option>
              <option value="2">2</option>
              <option value="3">3</option>
              <option value="4">4</option>
              <option value="5">5</option>
            </select>
          </div>
          <div className="col-md pb-2">
            <b>Partagé:</b>
            <select className="form-control"
             onChange={(e)=>{
               this.setState({shared:e.target.value},()=>this.get_medecins());
               }}>
              <option value="">tous</option>
              <option value="1">non partagé</option>
              <option value="2">partagé</option>
            </select>
          </div>
        </div>
      </div>
      <List
       medecins={this.props.medecins}
       length={this.props.length}
       other={this.props.other}
       PDFLink={this.PDFLink}
       PDFSingle={this.PDFSingle}
       MedecinsList={this.MedecinsList}
       />
      <Pagination
        pages={this.props.pages}
        page={this.props.page}
        next={this.props.next}
        previous={this.props.previous}
        getByPage={this.get_by_page}
      />
      </React.Fragment>
    )
  }


 
}

export default Filters
