
class Urls  {
  constructor(){
    this.user='/accounts/api/current';
    this.pays='/regions/pays/api';
    this.rapports='/rapports/api';
    this.commerciaux='/accounts/api/';
    this.medecins='/medecins/api/';
    this.specialites='/accounts/api/specialite/';
    this.classifications='/accounts/api/classifications/';
    this.produits='/produits/api/';
    this.orders='/orders/api/';
    this.exits='/orders/exits/api/';
  }

  getCookie(name) {
    var cookieValue = null;
    if (document.cookie && document.cookie !== '') {
        var cookies = document.cookie.split(';');
        for (var i = 0; i < cookies.length; i++) {
            var cookie = cookies[i].trim();
            // Does this cookie string begin with the name we want?
            if (cookie.substring(0, name.length + 1) === (name + '=')) {
                cookieValue = decodeURIComponent(cookie.substring(name.length + 1));
                break;
            }
        }
    }
    return cookieValue;
  }
}

export default Urls
