import React, { Component } from 'react'

class Pagination extends Component {


  previous_page=()=>{
    if(this.props.previous>0)
    return(
      <li className="page-item">
        <a className="page-link" onClick={(e)=>this.props.getByPage(this.props.previous)} aria-label="Previous">
          <span aria-hidden="true">&laquo;</span>
        </a>
      </li>
    )
  }


  next_page=()=>{
    if(this.props.next>0)
    return(
      <li className="page-item">
        <a className="page-link" onClick={(e)=>this.props.getByPage(this.props.next)} aria-label="Next">
          <span aria-hidden="true">&raquo;</span>
        </a>
      </li>
    )
  }


  pagination_items=()=>{
    var pagination=[];
    if(this.props.pages>0)
    for (let i=1;i<=this.props.pages;i++)
      pagination.push(
        <li className={(i==this.props.page)?"page-item active" : "page-item"} onClick={(e)=>this.props.getByPage(i)}><a className="page-link">{i}</a></li>
      )
      return pagination
  }


  render() {
    return (
      <div className="my-4 text-center">
        <ul className="pagination mx-auto justify-content-center">
          {this.previous_page()}
          {this.pagination_items()}
          {this.next_page()}
        </ul>
      </div>
    )
  }
}

export default Pagination
