import React ,{useState} from 'react'
import axios from 'axios'
import { faStar} from "@fortawesome/free-solid-svg-icons";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";

export default function Note({rapport}) {
    
    const [rnote, setrnote] = useState(rapport.note)

    const send_note=async(n)=>{
        axios.get(`rapports/${rapport.id}/note/set/?note=${n}`)
        .then(response=>{
            if (response.status==200)
            {   
                setrnote(n)
            }
            else 
                alert("please try again")    
        })
        .catch(error=>{
           console.log(error);
           alert("please try again")  
        })
    }
    return (
        <div class="py-2">
            {[1,2,3,4,5].map(note=>{
                return (
                    <small onClick={()=>{send_note(note)}}><FontAwesomeIcon icon={faStar} color={ rnote >= note ? "orangered" : "gray" } /></small>
                )
            })}
        </div>
    )
}
