import React, { Component } from 'react'
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faPrint,faImage} from "@fortawesome/free-solid-svg-icons";

class List extends Component {

  render() {
    return (
      <React.Fragment>
        <div className="container py-2 text-secondary">
          affichage de <b>({this.props.length})</b> resultats
          <span dangerouslySetInnerHTML={{__html:this.props.other}}></span> &nbsp;
            <a className="btn" href={this.props.PDFLink()} target="__blank"><FontAwesomeIcon icon={faPrint} /> liste des visites </a> &nbsp;
            <a className="btn" href={this.props.MedecinsList()} target="__blank"><FontAwesomeIcon icon={faPrint} /> liste des medecins </a>
        </div>
      <div className="container-fluid">
        <table className="table table-bordered table-striped table-hover">
          <thead>
            <tr>
              <th scope="col">region</th>
              <th scope="col">délégué</th>
              <th scope="col">nom</th>
              <th scope="col">specialite</th>
              <th scope="col">telephone</th>
              <th scope="col">adresse</th>
              <th scope="col">visites</th>
            </tr>
          </thead>
          <tbody>
          {this.props.medecins.map(medecin=>(
            <tr key={medecin.id}>
              <td scope="col">{medecin.region}</td>
              <td scope="col">{medecin.commercial} </td>
              <td scope="col">
                 <a href={`/admin/medecins/medecin/${medecin.id}/change/`} target="_blank">{medecin.id}</a> {medecin.nom}  <br/>
                 {medecin.last_visite} <br/>
                 {medecin.stock.map(visiteproduct=>(
                    <>
                    <span> {visiteproduct.product.nom} ({visiteproduct.qtt}) </span> &nbsp;
                    </>
              ))}
              </td>
              <td scope="col">{medecin.specialite} {medecin.classification}</td>
              <td scope="col">{medecin.telephone}/{medecin.email}</td>
              <td scope="col">{medecin.adresse}</td>
              <td scope="col">
              <div dangerouslySetInnerHTML={{__html:medecin.visites}}></div>
              <a className="btn" href={`/medecins/visites/PDF/${medecin.id}/${this.props.PDFSingle()}`} target="__blank"><FontAwesomeIcon icon={faPrint} /></a>
              </td>
            </tr>
          ))}

          </tbody>
        </table>
      </div>
      </React.Fragment>
    )
  }
}
//
export default List
